  <HEADER encrypted="1" encrypted_ver="1" build="0.0704.1001.0000.13.0" user="user" computer="WIN-856EDCD152U" date="2025.08.02 15'54'03" map_xs="100" map_ys="100" north_angle="0" extra_map_edge="1" tileset="volcanic" environment="Volcanic_final_AC8_Split_Forces" players="6" name="Жгучие перевалы" id="zhguchie_perevali" style="0" description="Эта область, по словам пришедших сюда жрецов квотлов, была одним из мест падения осколка корабля ложных богов, поэтому многие путешественники ищут инопланетные реликты в этой области, такие как древние дроны и автоматоны, не требующие пилотов. Однако многие находили здесь лишь свою гибель, из-за пришедших после падения огненных тварей, таких как пламенные драконы, до последнего сторожащие свои гнезда и неизвестный барьер, скрывающий путь в подземную часть неизвестных руин." enable_dominance="1" preview_image_ext="tga" version="12" allowable_game_styles="4294967295" default_game_style="-1" victory="255" elimination="1" allies="12" living_world_bird="22" force_rush_rules_disable="0" does_override_teamstyle="0" teamstyle_override_value="0" starts_required="0" starts_no_pick="0" show_all_villages="1" generate_script="0" num_villages="18" num_special="22">
